def isValid(word):
    if len(word) < 3:
        return False

    vowels = set("aeiouAEIOU")
    has_vowel = False
    has_consonant = False

    for ch in word:
        if ch.isalpha():
            if ch in vowels:
                has_vowel = True
            else:
                has_consonant = True
        elif ch.isdigit():
            continue
        else:
            return False

    return has_vowel and has_consonant
